# Use a dedicated "finish" tool to capture structured completion.
# The model calls it when it has a final answer, providing both
# the answer and a confidence rating.

FINISH_TOOL = {
    "name": "finish",
    "description": (
        "Call this tool when you have a final answer. "
        "Do NOT call it until you are confident the task is complete."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "answer": {
                "type": "string",
                "description": "The complete final answer to the task",
            },
            "confidence": {
                "type": "string",
                "enum": ["high", "medium", "low"],
                "description": "How confident you are in this answer",
            },
        },
        "required": ["answer", "confidence"],
    },
}


def check_structured_completion(response) -> dict | None:
    """
    Returns the finish tool's input if the model called it, else None.
    """
    for block in response.content:
        if block.type == "tool_use" and block.name == "finish":
            return block.input  # {"answer": "...", "confidence": "high"}
    return None


# In the loop:
completion = check_structured_completion(response)
if completion:
    return {
        "done": True,
        "answer": completion["answer"],
        "confidence": completion["confidence"],
    }

import pathlib
import subprocess
from typing import Callable


# --- File system checks ---

def file_exists(path: str) -> bool:
    return pathlib.Path(path).exists()

def file_nonempty(path: str) -> bool:
    p = pathlib.Path(path)
    return p.exists() and p.stat().st_size > 0

def file_contains(path: str, substring: str) -> bool:
    try:
        return substring in pathlib.Path(path).read_text()
    except OSError:
        return False


# --- Test suite check ---

def tests_pass(test_command: list[str]) -> bool:
    """Run a test command; return True iff it exits with code 0."""
    result = subprocess.run(
        test_command,
        capture_output=True,
        timeout=60,
    )
    return result.returncode == 0


# --- HTTP check ---

def api_returns_ok(url: str) -> bool:
    import urllib.request
    try:
        with urllib.request.urlopen(url, timeout=10) as resp:
            return 200 <= resp.status < 300
    except Exception:
        return False


# --- Composing checks into a goal predicate ---

def make_goal_predicate(checks: list[Callable[[], bool]]) -> Callable[[], bool]:
    """All checks must pass for the goal to be satisfied."""
    def predicate() -> bool:
        return all(check() for check in checks)
    return predicate


# Example: coding task that must write a file and pass tests
is_coding_goal_done = make_goal_predicate([
    lambda: file_nonempty("/workspace/solution.py"),
    lambda: tests_pass(["python", "-m", "pytest", "tests/test_solution.py", "-q"]),
])

SELF_ASSESS_SYSTEM = """
You are a strict quality checker. Given a task and the agent's work so far,
determine whether the task is fully complete. Return JSON only.
"""

SELF_ASSESS_SCHEMA = {
    "type": "object",
    "properties": {
        "satisfied": {"type": "boolean"},
        "gap": {
            "type": "string",
            "description": "What is missing or wrong (empty string if satisfied=true)"
        },
        "confidence": {"type": "string", "enum": ["high", "medium", "low"]},
    },
    "required": ["satisfied", "gap", "confidence"],
}


def self_assess_completion(
    client,
    original_task: str,
    messages: list[dict],
) -> dict:
    """
    Ask the model to evaluate whether its own work satisfies the task.
    Uses a separate system prompt to act as an impartial reviewer.
    """
    # Build a summary of what the agent has done so far
    work_summary = []
    for m in messages[1:]:  # skip the original user task
        if m["role"] == "assistant":
            for block in (m["content"] if isinstance(m["content"], list) else []):
                if hasattr(block, "type") and block.type == "text":
                    work_summary.append(f"[agent]: {block.text[:500]}")

    prompt = (
        f"Task: {original_task}\n\n"
        f"Work done so far:\n" + "\n".join(work_summary[-5:]) +  # last 5 agent turns
        "\n\nIs the task complete? Return JSON."
    )

    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        system=SELF_ASSESS_SYSTEM,
        messages=[{"role": "user", "content": prompt}],
    )
    import json
    return json.loads(response.content[0].text)


# Usage: after natural completion, double-check with self-assessment
assessment = self_assess_completion(client, task, messages)
if not assessment["satisfied"]:
    # Continue the loop: append the gap as a new user message
    messages.append({
        "role": "user",
        "content": f"Your answer is not yet complete. Gap: {assessment['gap']}"
    })

from dataclasses import dataclass
from typing import Callable


@dataclass
class CompletionDetector:
    """
    Combines all four detection strategies. Configure which are
    active via the constructor — external and self-assessment are
    optional, model signal is always checked.
    """
    goal_predicate: Callable[[], bool] | None = None   # external verification
    use_self_assessment: bool = False
    finish_tool_name: str = "finish"

    def check(self, response, messages: list[dict], client=None, task: str = "") -> dict:
        """
        Returns {"done": True, "answer": ..., "source": ...} or {"done": False}.
        """
        # 1. Structured output — highest priority (explicit model signal)
        for block in response.content:
            if block.type == "tool_use" and block.name == self.finish_tool_name:
                return {"done": True, "answer": block.input.get("answer", ""),
                        "source": "finish_tool"}

        # 2. External verification — check before model signal for efficiency
        if self.goal_predicate is not None and self.goal_predicate():
            answer = next(
                (b.text for b in response.content if b.type == "text"), "")
            return {"done": True, "answer": answer, "source": "external"}

        # 3. Model signal (end_turn, no tool calls)
        tool_calls = [b for b in response.content if b.type == "tool_use"]
        model_done = response.stop_reason == "end_turn" and not tool_calls

        if model_done:
            answer = next(
                (b.text for b in response.content if b.type == "text"), "")

            # 4. Self-assessment — only if model declared done
            if self.use_self_assessment and client:
                assessment = self_assess_completion(client, task, messages)
                if not assessment["satisfied"]:
                    return {"done": False}

            return {"done": True, "answer": answer, "source": "model_signal"}

        return {"done": False}
